mapper.sql:
SELECT POST_ID, TITLE, CONTENTS, REG_ID, REG_DATE, COMMUNITY_ID, HIDDEN_INFO, HIT_COUNT, IS_NOTICE
FROM TB_BOARD


        AND REG_ID = #{regId}


        AND TITLE LIKE '%' || #{title} || '%'


        AND COMMUNITY_ID = #{communityId}


ORDER BY POST_ID DESC

mapper.select:
SELECT POST_ID, TITLE, CONTENTS, REG_ID, REG_DATE, COMMUNITY_ID, HIDDEN_INFO, HIT_COUNT, IS_NOTICE
FROM TB_BOARD
WHERE POST_ID = #{postId}
